var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"칫, 쇳덩어리가 왜 이렇게 가벼워? 힘을 주기도 전에 날아가버리잖아.","JPN":"チッ、鉄の塊のくせになんて軽いんだ？　まだ力も入れてないのにぶっ飛んだじゃないか。","ENG":"Hmph, that was light for a chunk of metal. It flew away even before I put in my full strength.","TWN":"嘖，不是鐵做的嗎？怎麼這麼輕？我拳頭都還沒碰到欸，他怎麼就先飛出去？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐야? 저 깡패…? 왜 저리 무식하게 세?","JPN":"何？　あのチンピラ……？　なんて力なの？","ENG":"What is she? A gangster or what...? Why is she so strong?","TWN":"哇賽？那個女流氓…？頭腦簡單四肢也太發達？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"이… 이럴 수가. 어떻게 이런 일이.","JPN":"こ、こんなことが……ありえるのか？","ENG":"Oh... Oh my. How can this happen?","TWN":"這…怎麼可能？怎麼會有這種事？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"난 경고했어. 변상하라고 했다간 다음은 너야.","JPN":"アタシは警告した。弁償しろとか言ったら、次はお前の番だ。","ENG":"I warned you. If you tell me to pay for the damage, you’re going to be next.","TWN":"我剛有事先警告過囉，要是敢叫我賠償下一個挨揍的就是你！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"당신… 이름이 뭐죠?","JPN":"あなた……お名前は？","ENG":"You... What’s your name?","TWN":"你…叫什麼名字？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"알아서 뭐하게?","JPN":"知ってどうする。","ENG":"What do you need my name for?","TWN":"知道我的名字要幹嘛？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그 차갑고 무신경한 태도. 역시 닮았어.","JPN":"その冷たくて無神経な態度。やっぱりそうだ。","ENG":"That cold, indifferent attitude. I knew it!","TWN":"那副傲嬌又粗線條的態度，完全一模一樣！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"당신은 내가 줄곧 생각해왔던 파벨라와 똑같아!","JPN":"あなたは私がずっと思い描いてたファヴェーラとそっくりだ！","ENG":"You’re the Fabella I’ve been looking for!","TWN":"你就是我一直在尋尋覓覓的帕貝拉！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"윽…?!","JPN":"うっ……！？","ENG":"Ngh...?!","TWN":"蛤…？！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"오빠, 이 녀석 맘에 안 드는데. 두들겨 패도 돼?","JPN":"兄さん、こいつ気に入らないんだけど、殴っていいか？","ENG":"Doma, I don’t like him. Can I beat him up?","TWN":"哥，我不喜歡這傢伙，可以開扁嗎？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"참아보렴, 동생아. 지금 감독님이 실려가면 의뢰인 분께서 곤란해지거든.","JPN":"我慢しなさい、妹よ。今監督が病院行きになったら、依頼人が困るから。","ENG":"Hold it, my sister. Our client will be in trouble if the director ends up in the hospital.","TWN":"妹妹，你先忍忍。萬一導演現在送急診的話，委託人會很困擾的。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"자네! 드라마 주인공에 도전해볼 생각 없나?","JPN":"君！　ドラマの主役に挑戦してみる気はないか？","ENG":"You! Don’t you want to be the lead of a TV series?","TWN":"我說你！你難道不想挑戰看看當連續劇女主角嗎？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐어…?!","JPN":"はあ……！？","ENG":"What...?!","TWN":"什麼…？！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"아니, 관심 없는데.","JPN":"いや、興味ない。","ENG":"Nope, not interested.","TWN":"不想，沒興趣。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"당연히 거절 못 하겠지! 그럼 어서 계약 절차를…!","JPN":"当然断れないだろう！　じゃあ、早速契約の手続きを……！","ENG":"Of course you’ll take the offer! Then let’s hurry with the contract...!","TWN":"我就知道你是不會拒絕的！那來簽合…！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"…응? 관심 없다고?","JPN":"……えっ？　興味ない？","ENG":"...Huh? You’re not interested?","TWN":"…你說什麼？沒興趣？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"잠깐. 이게 어떤 자리인지 알긴 하고 말하는 거야?","JPN":"待て。これがどんな役かわかってはいるのか？","ENG":"Wait. Do you even know what kind of position this is?","TWN":"這麼好的機會，你知道你在說什麼嗎？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"내 작품의 주인공이 되는 순간, 온 연예계와 광고 스폰서들이 당신을 주목할 거라고!","JPN":"私の作品の主人公になれば、芸能界とスポンサーの注目を集めるのは造作もないはずだ！","ENG":"If you become the lead of my work, you’ll attract attention from the entire entertainment industry!","TWN":"只要你成為我戲裡的女主角，整個演藝圈和贊助商就會立刻關注你！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그게 뭐가 좋은 건데?","JPN":"それのなにがいいんだ？","ENG":"What’s so good about that?","TWN":"那有什麼好的？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어차피 재미없는 연기만 하루종일 연습해야 하는 거잖아? 귀찮아.","JPN":"どうせ一日中つまらない演技ばっかり練習しないといけないんだろう？　面倒くさい。","ENG":"Acting’s not fun, and I’ll have to practice it all day long. So bothersome.","TWN":"那不就整天都只能練習無聊的演戲？我不喜歡。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"알고 있었던 거니? 난 네가 드라마를 사실이라고 믿는 줄 알았단다.","JPN":"知っていたのか？　私はユマがドラマを本当だと信じているのかと思ったよ。","ENG":"You actually knew that TV series weren’t real? I thought you saw them as real stories.","TWN":"你知道是在演戲？我還以為你把連續劇都當成真的。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};